remediation.terraform:
# Replace full admin attachment with a non-admin policy (ensure AdministratorAccess is not attached)
resource "aws_iam_role_policy_attachment" "<example_resource_name>" {
  role       = "<example_resource_name>"
  policy_arn = "arn:aws:iam::aws:policy/ReadOnlyAccess"  # FIX: avoids '*:*' admin privileges; replace AdministratorAccess
}

# Terraform: Inline role policy without '*:*' privileges
resource "aws_iam_role_policy" "<example_resource_name>" {
  name = "leastpriv"
  role = "<example_resource_name>"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Effect   = "Allow"
      Action   = "s3:ListBucket"                   # Critical: specific action, not "*"
      Resource = "arn:aws:s3:::<example_resource_name>"  # Critical: specific resource, not "*"
    }]
  })
}

# Terraform: Managed policy without '*:*' admin privileges
resource "aws_iam_policy" "<example_resource_name>" {
  name   = "<example_resource_name>"
  policy = jsonencode({
    Version   = "2012-10-17"
    Statement = [{
      Effect   = "Allow"
      Action   = "iam:GetUser"  # CRITICAL: not "*" or "*:*"; removes admin privileges
      Resource = "*"             # CRITICAL: paired with specific action to avoid full admin
    }]
  })
}

# IAM group with no AdministratorAccess attachment
resource "aws_iam_group" "<example_resource_name>" {
  name = "<example_resource_name>"
  # Critical: do NOT create any aws_iam_group_policy_attachment with
  # policy_arn = "arn:aws:iam::aws:policy/AdministratorAccess" for this group
}

# Terraform: Replace the risky inline policy with least-privilege actions
resource "aws_iam_user_policy" "<example_resource_name>" {
  name = "<example_resource_name>"
  user = "<example_resource_name>"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Effect   = "Allow"
      Action   = "ec2:DescribeInstances"  # FIX: only non-privilege-escalation action; remove IAM/STS escalation actions
      Resource = "*"                       # FIX: safe read-only scope
    }]
  })
}

resource "aws_iam_role_policy" "<example_resource_name>" {
  name = "<example_resource_name>-policy"
  role = "<example_resource_name>"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Effect   = "Allow"
      Action   = ["cloudtrail:DescribeTrails"] # Critical: replace 'cloudtrail:*' with specific action(s) to remove full service access
      Resource = "*"
    }]
  })
}

# Terraform: Replace wildcard resource with a specific role ARN
resource "aws_iam_policy" "<example_resource_name>" {
  name   = "<example_resource_name>"
  policy = jsonencode({
    Version   = "2012-10-17"
    Statement = [{
      Effect   = "Allow"
      Action   = "sts:AssumeRole"
      Resource = "arn:aws:iam::<example_account_id>:role/<example_resource_name>" // CRITICAL: restrict to a specific role ARN to remove wildcard
    }]
  })
}

resource "aws_iam_policy" "<example_resource_name>" {
  name   = "<example_resource_name>"
  # Critical: Deny all actions so the policy cannot allow privilege escalation
  policy = jsonencode({
    Version   = "2012-10-17",
    Statement = [{
      Effect   = "Deny",
      Action   = "*",
      Resource = "*"
    }]
  })
}

# IAM Role without AdministratorAccess
resource "aws_iam_role" "<example_resource_name>" {
  assume_role_policy = <<POLICY
{
  "Version": "2012-10-17",
  "Statement": [{
    "Effect": "Allow",
    "Principal": {"Service": "ec2.amazonaws.com"},
    "Action": "sts:AssumeRole"
  }]
}
POLICY

  managed_policy_arns = [] # Critical: ensures "AdministratorAccess" is NOT attached
}

# Terraform snippet to prevent cross-account access on a role
resource "aws_iam_role" "<example_resource_name>" {
  name = "<example_resource_name>"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Effect = "Allow"
      Principal = {
        AWS = "arn:aws:iam::<example_account_id>:root" # Critical: trust only the same account to avoid cross-account access
      }
      Action = "sts:AssumeRole"
    }]
  })
}

# IAM role trust policy with confused deputy protection
resource "aws_iam_role" "<example_resource_name>" {
  name = "<example_resource_name>"

  # CRITICAL: Condition restricts service to this account to prevent cross-service confused deputy
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect    = "Allow"
        Principal = { Service = "<service>.amazonaws.com" }
        Action    = "sts:AssumeRole"
        Condition = {
          StringEquals = { "aws:SourceAccount" = "<ACCOUNT_ID>" }
        }
      }
    ]
  })
}

# IAM user without console password
resource "aws_iam_user" "user" {
  name = "<example_resource_name>"
  # Critical: Do NOT create an aws_iam_user_login_profile resource.
  # Without a login profile, no console password is set, so the check passes.
}

# Attach an inline policy to block long-term creds from non-IAM/STS services
resource "aws_iam_user_policy" "deny_non_iam_sts_longterm" {
  name = "DenyNonIamStsWithLongTermCreds"
  user = "<example_resource_name>"  # Critical: target the affected IAM user

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Effect    = "Deny"
      NotAction = ["iam:*", "sts:*"]
      Resource  = "*"
      Condition = {
        Null = { "aws:TokenIssueTime" = "true" } # Critical: denies when no session token (long-lived creds)
      }
    }]
  })
}

# IAM policy without '*:*' administrative privileges
resource "aws_iam_policy" "<example_resource_name>" {
  name   = "<example_resource_name>"
  policy = jsonencode({
    Version   = "2012-10-17"
    Statement = [
      {
        Effect   = "Allow"
        Action   = "iam:GetAccountSummary"   # Critical: specific action, not '*'
        Resource = "*"                        # Critical: avoids '*:*' admin privileges
      }
    ]
  })
}

# Inline IAM policy without kms:* full access
resource "aws_iam_user_policy" "<example_resource_name>" {
  name = "<example_resource_name>-policy"
  user = "<example_resource_name>"

  policy = jsonencode({
    Version   = "2012-10-17"
    Statement = [{
      Effect   = "Allow"
      Action   = [
        "kms:Encrypt" # CRITICAL: replace 'kms:*' with specific action(s) to remove full access
      ]
      Resource = "*"
    }]
  })
}

# Enforce IAM password expiration within 90 days
resource "aws_iam_account_password_policy" "example" {
  max_password_age = 90  # Critical: enforces password expiration <= 90 days to pass the check
}

resource "aws_iam_account_password_policy" "<example_resource_name>" {
  minimum_password_length = 14  # Critical: enforces minimum password length >=14
}

# Enforce at least one number in IAM user passwords
resource "aws_iam_account_password_policy" "<example_resource_name>" {
  require_numbers = true  # Critical: requires at least one number in passwords
}

resource "aws_iam_account_password_policy" "<example_resource_name>" {
  password_reuse_prevention = 24  # Critical: require last 24 passwords cannot be reused
}

resource "aws_iam_account_password_policy" "<example_resource_name>" {
  require_symbols = true  # Critical: require at least one symbol in passwords
}

resource "aws_iam_account_password_policy" "<example_resource_name>" {
  require_uppercase_characters = true  # Critical: enforce at least one uppercase letter
}

# Terraform: ensure AWSCloudShellFullAccess is NOT attached
resource "aws_iam_user_policy_attachment" "<example_resource_name>" {
  count      = 0  # Critical: prevents creation, ensuring the policy is detached/not attached
  user       = "<example_resource_name>"
  policy_arn = "arn:aws:iam::aws:policy/AWSCloudShellFullAccess"  # Denied policy
}

# IAM policy without CloudTrail wildcard access
resource "aws_iam_policy" "<example_resource_name>" {
  name   = "<example_resource_name>"
  policy = jsonencode({
    Version   = "2012-10-17"
    Statement = [{
      Effect   = "Allow"
      Action   = "cloudtrail:DescribeTrails" # Critical: replaces 'cloudtrail:*' with a specific action, removing full access
      Resource = "*"
    }]
  })
}

# Customer managed policy without kms:* full access
resource "aws_iam_policy" "<example_resource_name>" {
  name   = "<example_resource_name>"
  policy = jsonencode({
    Version   = "2012-10-17"
    Statement = [{
      Effect   = "Allow"
      Action   = ["kms:Encrypt"]  # FIX: remove 'kms:*'; allow only specific KMS action
      Resource = "arn:aws:kms:<REGION>:<ACCOUNT_ID>:key/<example_resource_id>"  # FIX: scope to a specific key
    }]
  })
}

resource "aws_iam_access_key" "<example_resource_name>" {
  user   = "<example_resource_name>"
  status = "Inactive" # Critical: disables the access key to ensure no active key is older than 90 days
}

# IAM user with console access disabled by not creating a login profile
resource "aws_iam_user" "<example_resource_name>" {
  name = "<example_resource_name>"
  # Critical: Do not define aws_iam_user_login_profile for this user -> no console access
}

# Ensure IAM access key is not active
resource "aws_iam_access_key" "<example_resource_name>" {
  user   = "<example_resource_name>"
  status = "Inactive"  # Critical: disables the key so it isn't active and cannot be flagged as never used
}

# Deactivate one IAM access key so the user has at most one active key
resource "aws_iam_access_key" "<example_resource_name>" {
  user   = "<example_resource_name>"
  status = "Inactive"  # Critical: deactivates this key to avoid 2 active keys
}

# Create an IAM SAML provider to satisfy the check
resource "aws_iam_saml_provider" "<example_resource_name>" {
  name                   = "<example_resource_name>"
  saml_metadata_document = file("<SAML_METADATA_XML_FILE>") # Critical: creates the SAML provider so the check passes
}

resource "aws_iam_account_password_policy" "<example_resource_name>" {
  require_lowercase_characters = true  # Critical: Enforces at least one lowercase letter in passwords
}

# Minimal IAM role plus attachment of the AWS managed SecurityAudit policy
resource "aws_iam_role" "example" {
  name               = "<example_resource_name>"
  assume_role_policy = <<POLICY
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Principal": { "AWS": "arn:aws:iam::<example_account_id>:root" },
      "Action": "sts:AssumeRole"
    }
  ]
}
POLICY
}

resource "aws_iam_role_policy_attachment" "security_audit" {
  role       = aws_iam_role.example.name
  policy_arn = "arn:aws:iam::aws:policy/SecurityAudit" # CRITICAL: attaches SecurityAudit to the role to pass the check
}

# IAM role with AWS Support access
resource "aws_iam_role" "example_resource_name" {
  name               = "example_resource_name"
  assume_role_policy = jsonencode({
    Version   = "2012-10-17",
    Statement = [{
      Effect    = "Allow",
      Principal = { AWS = "arn:aws:iam::<example_account_id>:user/<example_resource_name>" },
      Action    = "sts:AssumeRole"
    }]
  })

  managed_policy_arns = [
    "arn:aws:iam::aws:policy/AWSSupportAccess"  # Critical: ensures this role has AWSSupportAccess (PASS)
  ]
}
